parameters.jsCode:
const response = $input.item.json;
const content = response.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : { resume_summary: content, key_skills: [], cover_letter: content };
} catch(e) {
  parsed = { resume_summary: content, key_skills: [], cover_letter: content };
}
return {
  resume_summary: parsed.resume_summary || '',
  key_skills: parsed.key_skills || [],
  cover_letter: parsed.cover_letter || '',
  generated_at: new Date().toISOString()
};
